export const BulkUpdateOpportunitiesAndPledgesBody = zod.object({
  ids: zod
    .array(zod.string())
    .min(1)
    .max(bulkUpdateOpportunitiesAndPledgesBodyIdsMax),
  patch: zod.object({
    ownerUserId: zod.string().nullish(),
    status: zod
      .enum(["open", "pledge", "cash_in", "dormant", "lost"])
      .describe(
        "Lifecycle status of an opportunity\/pledge row.\n  open    — actively in the funnel, not yet committed\n  pledge  — funder has committed (stage in conditional\/verbal\/written)\n  cash_in — fully paid (stage=cash_in or sum of payments >= awarded)\n  dormant — paused; sticky user override\n  lost    — declined\/withdrawn; sticky user override\nStatus is auto-derived from stage + payments on every write EXCEPT when\nthe row is already dormant\/lost (sticky overrides — only clear when the\nuser explicitly picks a different value).\n",
      )
      .nullish(),
    stage: zod
      .enum([
        "cold_lead",
        "warm_lead",
        "in_conversation",
        "convince",
        "conditional_commitment",
        "probable_renewal",
        "verbal_commitment",
        "written_commitment",
        "cash_in",
      ])
      .nullish(),
    type: zod.enum(["solicitation", "renewal", "open_application"]).nullish(),
    wasPledge: zod.boolean().nullish(),
    isConditional: zod.boolean().nullish(),
    actualCompletionDate: zod
      .string()
      .date()
      .nullish()
      .describe(
        "Optional close date when bulk-setting status to cash_in\/lost. Left null is allowed to support historical cleanup workflows.",
      ),
    coveredFiscalYears: zod
      .array(zod.string())
      .optional()
      .describe(
        "Set of fiscal-year slugs (e.g. 'fy2026') to attach to each opportunity via pledge_allocations. Combined with coveredFiscalYearsMode.",
      ),
    coveredFiscalYearsMode: zod
      .enum(["replace", "append"])
      .optional()
      .describe(
        "replace = wipe existing pledge_allocations on each opp and recreate one minimal row per FY (DESTRUCTIVE: loses subAmount\/intendedUsage on those rows). append = add allocations only for FYs not already present.",
      ),
    intendedUsage: zod
      .enum([
        "gen_ops",
        "growth",
        "school_startup",
        "teacher_training",
        "project",
      ])
      .optional()
      .describe(
        "Sets the intended usage on every pledge_allocations row of each opportunity. Existing allocation rows are updated to this value; if an opportunity has no allocations, one is created carrying this usage.",
      ),
    fundableProjectId: zod
      .string()
      .nullish()
      .describe(
        "Fundable project to link on every pledge_allocations row, applied alongside intendedUsage. Only honored when intendedUsage = 'project'; for any other usage the allocations' fundable_project_id is cleared to null.",
      ),
  }),
});

